export function getQuickReferenceNotes(framework){const baseNotes={previewValue:"Same as defaultValue; for Mapping UI only.",valueMapping:"Maps prop values to design system states/variants. Check component directory first for design system files."};switch(framework){case"swiftui":return{...baseNotes,name:'Use the struct name that conforms to View protocol (e.g., "struct ButtonView: View" → "ButtonView"). Never use generic names.',required:"Check if property has default value or is optional (Type?). Properties without defaults and not optional are required.",defaultValue:"Look for property initializers and default parameter values in init(). Supports string | number | boolean | object | array."};case"jetpack-compose":return{...baseNotes,name:'Use the @Composable function name (e.g., "@Composable fun PrimaryButton()" → "PrimaryButton"). Never use generic names.',required:"Check if parameter has default value or is nullable. Parameters without defaults and not nullable are required.",defaultValue:"Look for default parameter values in @Composable function signature. Supports string | number | boolean | object | array."};case"angular":return{...baseNotes,name:'Extract from @Component decorator or class name. Use the selector as component name (e.g., "app-button").',required:"Check constructor parameters and @Input() decorators. Properties without defaults are required.",defaultValue:"Look in constructor default parameters, property initializers, and ngOnInit method.",attr:"Maps prop to a concrete HTML attribute.",directives:"Array of CUSTOM PROJECT directive dependencies with path and selector. ONLY include directives defined within the project (relative paths starting with ./). EXCLUDE: Angular built-in, third-party, Material/Flex Layout directives.",module:"Path to module file if component is defined in a module."};case"flutter":return{...baseNotes,name:'Use the class name that extends StatelessWidget or StatefulWidget (e.g., "CustomButton", "CardWidget").',required:"Check constructor parameters. Required parameters without defaults are required props.",defaultValue:"Look for default parameter values in constructor. Supports string | number | boolean | object | array."};case"react-native":return{...baseNotes,name:"Component name extraction: For direct exports use component name, for re-exports derive from filename.",required:"Set to true for PropTypes.*.isRequired props. Check TypeScript interfaces for required properties.",defaultValue:"Supports string | number | boolean | object | array. Not allowed for node and function types.",attr:'Maps prop to a concrete attribute (e.g., "source" for Image).'};default:return{...baseNotes,name:'Component name extraction: 1) For direct exports use "ComponentName". 2) For re-exports derive from filename. 3) For named exports use the exported name.',required:"Set to true for PropTypes.*.isRequired props. Check TypeScript interfaces for required properties.",defaultValue:"Supports string | number | boolean | object | array. Not allowed for node and function types.",attr:"Maps prop to a concrete HTML attribute (e.g., 'src', 'href')."}}}export function getUsagePatterns(framework){const base='Write entries to locofy.config.json under a top-level "components" array.';switch(framework){case"swiftui":return[base,'SwiftUI component: { "path": "./Sources/Components/ButtonView.swift", "name": "ButtonView", "props": [...] }','SwiftUI view with bindings: { "path": "./Views/SettingsView.swift", "name": "SettingsView", "props": [{"name": "isEnabled", "dataType": "boolean", "propType": 1}] }'];case"jetpack-compose":return[base,'Compose component: { "path": "./app/src/main/java/com/example/ui/Button.kt", "name": "PrimaryButton", "props": [...] }','Compose with slots: { "path": "./ui/components/Card.kt", "name": "CardComponent", "props": [{"name": "content", "dataType": "node", "propType": 5}] }'];case"angular":return[base,'Angular component: { "path": "./src/button/button.component.ts", "name": "ButtonComponent", "props": [...], "directives": [...] }','Angular directive: { "path": "./src/loading.directive.ts", "module": "./src/form-field.module.ts" }'];case"flutter":return[base,'Flutter widget: { "path": "./lib/widgets/button.dart", "name": "CustomButton", "props": [...] }','Flutter stateful: { "path": "./lib/components/counter.dart", "name": "CounterWidget", "props": [...] }'];case"react-native":return[base,'React Native component: { "path": "./src/components/Button.tsx", "name": "Button", "props": [...] }','React Native with image: { "path": "./components/Avatar.tsx", "name": "Avatar", "props": [{"name": "source", "dataType": "object", "propType": 1, "imageResolveType": "require"}] }'];default:return[base,'React/Vue entry: { "path": "./src/components/Button.tsx", "name": "Button", "props": [...] }']}}export function getWorkflowSteps(framework){const commonStart=["1. User mentions one or more component files","2. Call generateComponentsConfig tool ONCE to get this schema","3. FOR EACH component file mentioned by user:","   a. Read and analyze the component file AND its directory to extract ALL prop types, interfaces, and design metadata:","      - FIRST: List files in component directory to identify design system files"],commonEnd=["   e. Predict mapping between code component and design component which user selected on plugin","      - Use the design component data sent below to help you predict the mapping","      - For component mapping, consider using name, image, list of props, structure, layout as hint","      - For prop mapping, consider using name, prop type, expected values as hint","      - Prefer map component prop to design prop than map to layer","   f. Validate the mapping result","      - Make sure the mapping result must pass all the VALIDATION CHECKLIST in the valueMapping field","      - Make sure the mapping result must pass all the VALIDATION CHECKLIST in the config field","   g. Build a component entry: { path, name, props }",'   h. Create or update locofy.config.json at workspace root with a top-level { "components": [...] }',"   i. Merge by (path + name): if an entry exists, update its props; otherwise append a new entry","4. Confirm completion and summarize the components written to locofy.config.json"];switch(framework){case"swiftui":return[...commonStart,"      - SwiftUI: Extract properties from struct definition (var/let declarations)","      - SwiftUI: Identify property wrappers: @Binding (input prop), @State (internal), @ObservedObject/@StateObject (observable)","      - SwiftUI: Check init() parameters for injectable properties","      - SwiftUI: Look for @ViewBuilder closures for slot/node props","      - SwiftUI: Identify enum types used for variants (e.g., ButtonStyle enum)","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:",'      - Use struct name that conforms to View (e.g., "struct PrimaryButton: View" → "PrimaryButton")',"      - For generic views, include the base name without generic parameters",'      - NEVER use generic names like "View1"',"   c. Identify additional SwiftUI metadata:","      - @Binding properties are INPUT props that parent can modify","      - @ViewBuilder parameters indicate slot/node props","      - Look for PreviewProvider structs to understand default values","      - Check for custom ViewModifier implementations","   d. For library components, check Swift Package dependencies",...commonEnd];case"jetpack-compose":return[...commonStart,"      - Compose: Extract parameters from @Composable function signature","      - Compose: Check for Modifier parameter (common styling prop)","      - Compose: Look for @Composable lambda parameters for slot/node props (e.g., content: @Composable () -> Unit)","      - Compose: Identify sealed class/enum used for variants","      - Compose: Check for remember/mutableStateOf for stateful props","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:",'      - Use @Composable function name (e.g., "@Composable fun FilledButton()" → "FilledButton")',"      - For overloaded composables, use the most specific/complete signature",'      - NEVER use generic names like "Component1"',"   c. Identify additional Compose metadata:","      - Parameters with @Composable lambda type are slot/node props","      - Modifier parameter is for styling (similar to className in web)","      - MutableState<T> or State<T> parameters indicate stateful props","      - Look for @Preview annotated functions to understand default values","      - Check for CompositionLocal usage for environment-like props","   d. For library components, check build.gradle dependencies",...commonEnd];case"angular":return[...commonStart,"      - Angular: Extract @Input() decorated properties from component class","      - Angular: Check constructor parameters with public/private modifiers","      - Angular: Look for property initializers and ngOnInit assignments for default values","      - Angular: Identify component dependencies via @Component.selector and imports","      - Angular CUSTOM PROJECT DIRECTIVE DETECTION:",'        * Import Analysis: Look for imports ending with "Directive" from RELATIVE PATHS ONLY',"        * EXCLUDE imports from @angular/*, node_modules, or absolute package paths","        * Constructor Dependencies: Check parameters with @Self, @Optional decorators","        * Template Analysis: If templateUrl exists, read the .html file to find CUSTOM directive usage","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:",'      - Extract class name from "export class ButtonComponent" → use "ButtonComponent"','      - If @Component.selector exists, can derive from selector (e.g., "ds-button" → "DsButtonComponent")','      - NEVER use "default" as the component name',"   c. For Angular components, identify additional metadata:","      - MANDATORY: Analyze CUSTOM PROJECT directive dependencies","      - EXCLUDE Angular built-in directives (ngIf, ngFor, mat-*, fx*, etc.)","      - Look for module file if component is declared in a specific module","      - Extract directive selector from @Directive decorator if file is a directive","   d. For library components, check package.json dependencies",...commonEnd.map((step=>step.includes("Build a component entry")?"   g. Build a component entry: { path, name, props, [directives], [module] }":step))];case"flutter":return[...commonStart,"      - Flutter: Extract constructor parameters from StatelessWidget/StatefulWidget class","      - Flutter: Check for required vs optional parameters","      - Flutter: Look for Widget parameters for slot/node props","      - Flutter: Identify enum types used for variants","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:","      - Use class name that extends StatelessWidget or StatefulWidget",'      - NEVER use generic names like "Widget1"',"   c. Identify additional Flutter metadata:","      - Widget parameters indicate slot/node props","      - Look for default parameter values in constructor","      - Check for ThemeData usage for styling props","   d. For library components, check pubspec.yaml dependencies",...commonEnd];case"react-native":return[...commonStart,"      - React Native: Examine PropTypes definitions (including .isRequired props)","      - React Native: Check TypeScript interfaces/types for component props","      - React Native: Look at function parameters and destructuring patterns","      - React Native: Check for StyleSheet usage for styling props","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:",'      - For "export default ComponentName" → use "ComponentName"',"      - For re-exports, derive from filename",'      - NEVER use "default" as the component name',"   c. For library components (e.g., react-native-paper):","      - Check package.json for exact library version","      - Use knowledge of component props for that version","   d. Handle image props:","      - Check if require() or {uri:} is used for image resolution","      - Set imageResolveType accordingly",...commonEnd];default:return[...commonStart,"      - UI Library component: If component is from a library, get all UI-related props","      - React/Vue: Examine PropTypes definitions (including .isRequired props)","      - React/Vue: Check TypeScript interfaces/types for component props","      - React/Vue: Look at function parameters and destructuring patterns","      - VALUE MAPPING DETECTION (for design system components):","        1. PRIMARY: Check component directory for .figma.ts files","        2. SECONDARY: Look for SCSS state files (*.states.scss)","        3. FALLBACK: Analyze component logic for conditional states","      - Include ALL props found, even internal/styling props","   b. Determine the correct component name:",'      - React/Vue: For "export default ComponentName" → use "ComponentName"',"      - React/Vue: For re-exports, derive from filename",'      - NEVER use "default" as the component name',"   c. For re-exported components, analyze the original component props:","      - Check package.json to identify the exact library version","      - Use knowledge of component props for that version","      - Include all relevant props with proper types, enums, default values","   d. For Higher-Order Components (HOCs), include both original and HOC-injected props",...commonEnd]}}